/* SQL ID : BbsInfoDAO.selectBbsInfo 설 명 : 게시판 정보 */ SELECT A.* , B.SBJCT_YR , B.SBJCT_SMSTR , B.CRS_MSTR_ID FROM ( SELECT A.BBS_ID , A.ORG_ID , A.BBSNM AS atclTitle , A.BBS_EXPLN , A.BBS_TYCD , A.BBS_LANG_CD , A.MENU_ID , A.MN_IMG_FILE_ID , A.ATFL_MAX_CNT , A.ATFL_MAXSZ , A.LIST_CNT , A.DELYN , A.RGTR_ID , A.REG_DTTM , A.MDFR_ID , A.MOD_DTTM , CASE WHEN A.BBS_REF_TYCD = 'TEAM' THEN (SELECT AA.SBJCT_ID FROM TB_LMS_TEAM_GRP AA WHERE AA.LRN_GRP_ID = (SELECT BBS_REF_TYPE_ID FROM TB_LMS_BBS WHERE BBS_ID = #{bbsId})) ELSE A.BBS_REF_TYPE_ID END AS SBJCT_ID FROM TB_LMS_BBS A WHERE 1=1 AND A.DELYN = 'N' AND A.BBS_LANG_CD = #{langCd} AND A.ORG_ID = #{orgId}
AND A.BBS_ID = #{bbsId}
) A LEFT JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID

