mapper.insert:
		/*
             SQL ID : BbsInfoDAO.insertBbsInfo
             설  명 : 게시판 정보 저장
         */

		INSERT INTO TB_LMS_BBS (
			  BBS_ID
	        , ORG_ID
	        , SBJCT_ID
	        , BBS_REF_TYPE_ID
	        , BBS_REF_TYCD
	        , BBSNM
	        , BBS_ENNM
	        , BBS_EXPLN
	        , BBS_TYCD
	        , BBS_BSC_LANG_CD
	        , MENU_CD
	        , MN_IMG_FILE_ID
	        , LIST_CNT
	        , ATFL_MAX_CNT
	        , ATFL_MAXSZ
	        , ATFL_USEYN
	        , UNIV_ID
	        , DELYN
	        , RGTR_ID
	        , REG_DTTM
	    ) VALUES (
	          #{bbsId}
	        , #{orgId}
	        , #{sbjctId}
	        , #{bbsRefTypeId}
	        , #{bbsRefTycd}
	        , #{bbsNm}
	        , #{bbsEnNm}
	        , #{bbsExpln}
	        , #{bbsTycd}
	        , #{bbsBscLangCd}
	        , #{menuCd}
	        , #{mnImgFileId}
	        , #{listCnt}
	        , #{atflMaxCnt}
	        , #{atflMaxsz}
	        , #{atflUseyn}
	        , #{univId}
	        , #{delyn}
	        , #{rgtrId}
	        , FN_DTTM()
	    )

mapper.update:
		/*
             SQL ID : BbsInfoDAO.updateBbsInfo
             설  명 : 게시판 수정
         */
		UPDATE TB_LMS_BBS
		SET

			  BBS_ID			= #{bbsId}
			, BBSNM				= #{bbsNm}

			, BBS_TYCD			= #{bbsRefTyCd}
			, BBS_BSC_LANG_CD	= #{bbsBscLangCd}









			, ATFL_USEYN			= #{atflUseyn}
			, ATFL_MAX_CNT			= #{atflMaxCnt}
			, ATFL_MAXSZ			= #{atflMaxSz}













			, MDFR_ID				= #{mdfrId}
			, MOD_DTTM				= FN_DTTM()
		WHERE BBS_ID = #{bbsId}

mapper.delete:
		/*
             SQL ID : BbsInfoDAO.deleteBbsInfo
             설  명 : 게시판 삭제
         */
		DELETE FROM TB_LMS_BBS
		WHERE BBS_ID = #{bbsId}

mapper.update:
		/*
             SQL ID : BbsInfoDAO.updateBbsInfoStdViewYn
             설  명 : 게시판 학생 공개 여부 수정
         */
		UPDATE TB_LMS_BBS
		SET
			  STDNT_INQYN	= #{stdViewYn}
			, MDFR_ID		= #{mdfrId}
			, MOD_DTTM		= FN_DTTM()
		WHERE BBS_ID = #{bbsId}

		/*
             SQL ID : BbsInfoDAO.updateBbsInfoUseYn
             설  명 : 게시판 사용여부 수정
         */
		UPDATE TB_LMS_BBS
		SET
			  USEYN		= #{useYn}
			, MDFR_ID	= #{mdfrId}
			, MOD_DTTM	= FN_DTTM()
		WHERE BBS_ID	= #{bbsId}

mapper.select:
/* SQL ID : BbsInfoDAO.listBbsInfoCourseAlarmTab 설 명 : 게시판 강의실 알림터 탭 */ WITH BBS_ODR AS ( SELECT 1 AS ODR, 'NOTICE' AS BBS_ID FROM DUAL UNION ALL SELECT 2, 'QNA' FROM DUAL UNION ALL SELECT 3, 'SECRET' FROM DUAL UNION ALL SELECT 4, 'PDS' FROM DUAL ) SELECT BBS_ID, CASE WHEN LINE_NO IS NULL THEN NULL ELSE BBS_ID END AS BBS_ID, CASE WHEN LINE_NO IS NULL THEN NULL ELSE BBSNM END AS BBSNM, TOTAL_CNT, NO_ANSWER_ATCL_CNT, CASE WHEN LINE_NO IS NULL THEN NULL ELSE SYS_USEYN END AS SYS_USEYN FROM ( SELECT LINE_NO , LISTAGG(A.BBS_ID, ',') WITHIN GROUP (ORDER BY A.BBS_ID) AS BBS_ID , MIN(A.BBS_ID) AS BBS_ID , MIN(A.BBSNM) AS BBSNM , SUM(A.TOTAL_CNT) AS TOTAL_CNT , SUM(A.NO_ANSWER_ATCL_CNT) AS NO_ANSWER_ATCL_CNT , MIN(A.SYS_USEYN) AS SYS_USEYN FROM ( SELECT ROW_NUMBER() OVER(ORDER BY CASE WHEN A.SYS_USEYN = 'N' THEN (SELECT ODR FROM BBS_ODR WHERE BBS_ID = A.BBS_ID) ELSE 9999 END) AS LINE_NO , A.BBS_ID , A.BBS_ID , A.BBSNM , A.TOTAL_CNT , A.NO_ANSWER_ATCL_CNT , A.SYS_USEYN FROM ( SELECT A.BBS_ID , A.BBS_ID , NVL(C.BBSNM, A.BBSNM) AS BBSNM , ( SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE BBS_ID = A.BBS_ID AND UP_ATCL_ID IS NULL AND DELYN = 'N'
AND ( RSRV_USEYN = 'N' OR RSRV_DTTM <= FN_DTTM() ) AND ( LOCKYN = 'N' OR RGTR_ID = #{viewerNo} )
) AS TOTAL_CNT , CASE WHEN A.BBS_ID IN ('QNA', 'SECRET') THEN ( SELECT COUNT(1) FROM TB_LMS_BBS_ATCL AA WHERE AA.BBS_ID = A.BBS_ID AND AA.UP_ATCL_ID IS NULL AND AA.DELYN = 'N' AND NOT EXISTS ( SELECT 1 FROM TB_LMS_BBS_ATCL WHERE BBS_ID = AA.BBS_ID AND UP_ATCL_ID = AA.ATCL_ID AND DELYN = 'N' )
AND ( AA.RSRV_USEYN = 'N' OR AA.RSRV_DTTM <= FN_DTTM() ) AND ( AA.LOCKYN = 'N' OR AA.RGTR_ID = #{viewerNo} )
) ELSE 0 END AS NO_ANSWER_ATCL_CNT , A.SYS_USEYN FROM TB_LMS_BBS A JOIN TB_HOME_BBS_RLTN B ON A.BBS_ID = B.BBS_ID AND B.CONTS_TYCD = 'COURSE' AND B.RLTN_REF_CD = #{crsCreCd} LEFT JOIN TB_HOME_BBS_INFO_LANG C ON A.BBS_ID = C.BBS_ID AND C.LANG_CD = #{langCd} WHERE A.SYS_USEYN = 'N' AND A.SYS_BSC_PVSNYN = 'Y' AND A.DELYN = 'N' AND A.USEYN = 'Y' AND A.BBS_ID IN ('NOTICE', 'PDS', 'QNA', 'SECRET') AND A.ORG_ID = #{orgId} -- 전체공지 게시판 UNION ALL SELECT A.BBS_ID , NULL AS BBS_ID , NVL(B.BBSNM, A.BBSNM) AS BBSNM , ( SELECT COUNT(1) FROM TB_LMS_BBS_ATCL WHERE BBS_ID = A.BBS_ID AND UP_ATCL_ID IS NULL AND DELYN = 'N'
AND ( RSRV_USEYN = 'N' OR RSRV_DTTM <= FN_DTTM() ) AND ( LOCKYN = 'N' OR RGTR_ID = #{viewerNo} )
) AS TOTAL_CNT , 0 AS NO_ANSWER_ATCL_CNT , A.SYS_USEYN FROM TB_LMS_BBS A LEFT JOIN TB_HOME_BBS_INFO_LANG B ON A.BBS_ID = B.BBS_ID AND B.LANG_CD = #{langCd} WHERE A.BBS_ID = #{bbsId} AND A.ORG_ID = #{orgId} ) A ) A WHERE A.BBS_ID IS NOT NULL GROUP BY ROLLUP(A.LINE_NO) ) A ORDER BY A.LINE_NO

/* SQL ID : BbsInfoDAO.listQnaSecretCountByLsnOdr 설 명 : 게시판 문의, 상담 현황 목록 */ WITH LESSON_SCHEDULE_T AS ( -- 강의 주차 SELECT A.LCTR_SCHDL_ID , A.LCTR_SCHDL_SEQ , A.LCTR_SYMD , A.LCTR_EYMD , ( SELECT COUNT(1) FROM TB_LMS_SBJCT_LCTR_SCHDL WHERE LCTR_EYMD < A.LCTR_SYMD AND SBJCT_ID = A.SBJCT_ID AND DELYN = 'N' ) + 1 AS GROUP_SEQ FROM TB_LMS_SBJCT_LCTR_SCHDL A WHERE A.SBJCT_ID = #{crsCreCd} AND A.DELYN = 'N' ) SELECT A.LESSON_SCHEDULE_ID_MIN , A.LESSON_SCHEDULE_ID_MAX , A.LESSON_SCHEDULE_ORDER_MIN , A.LESSON_SCHEDULE_ORDER_MAX , A.LESSON_START_DT_MIN , A.LESSON_END_DT_MAX , COUNT(B.ATCL_ID) AS ATCL_CNT FROM ( SELECT A.GROUP_SEQ , (SELECT LCTR_SCHDL_ID FROM LESSON_SCHEDULE_T WHERE GROUP_SEQ = A.GROUP_SEQ AND LCTR_SCHDL_SEQ = MIN(A.LCTR_SCHDL_SEQ)) AS LESSON_SCHEDULE_ID_MIN , (SELECT LCTR_SCHDL_ID FROM LESSON_SCHEDULE_T WHERE GROUP_SEQ = A.GROUP_SEQ AND LCTR_SCHDL_SEQ = MAX(A.LCTR_SCHDL_SEQ)) AS LESSON_SCHEDULE_ID_MAX , MIN(A.LCTR_SCHDL_SEQ) AS LESSON_SCHEDULE_ORDER_MIN , MAX(A.LCTR_SCHDL_SEQ) AS LESSON_SCHEDULE_ORDER_MAX , MIN(LCTR_SYMD) AS LESSON_START_DT_MIN , MAX(LCTR_EYMD) AS LESSON_END_DT_MAX FROM LESSON_SCHEDULE_T A GROUP BY GROUP_SEQ ) A LEFT JOIN ( SELECT A.ATCL_ID , A.FRST_INQ_DTTM FROM TB_LMS_BBS_ATCL A JOIN TB_LMS_BBS B ON A.BBS_ID = B.BBS_ID AND B.SYS_USEYN = 'N' AND B.SYS_BSC_PVSNYN = 'Y' AND B.DELYN = 'N' AND B.USEYN = 'Y' AND B.ORG_ID = #{orgId}
AND B.BBS_ID = 'QNA'
AND B.BBS_ID = 'SECRET'
WHERE A.UP_ATCL_ID IS NULL AND A.DELYN = 'N' AND EXISTS ( SELECT 1 FROM TB_HOME_BBS_RLTN WHERE BBS_ID = A.BBS_ID AND CONTS_TYCD = 'COURSE' AND RLTN_REF_CD = #{crsCreCd} )
AND A.RGTR_ID = #{rgtrId}
) B ON LEFT(B.FRST_INQ_DTTM, 8) BETWEEN LEFT(A.LESSON_START_DT_MIN, 8) AND LEFT(A.LESSON_END_DT_MAX, 8) GROUP BY A.GROUP_SEQ ORDER BY A.GROUP_SEQ

/* SQL ID : BbsInfoDAO.listTeamBbsId 설 명 : 게시판 팀 목록 */ SELECT A.TEAM_ID , A.TEAMNM , C.BBS_ID FROM TB_LMS_TEAM A JOIN TB_LMS_TEAM_CTGR B ON A.TEAM_TYCD = B.TEAM_TYCD AND B.TEAM_BBS_YN = 'Y' AND B.TEAM_CPST_CMPTNYN = 'Y' AND B.SBJCT_ID = #{crsCreCd}
AND A.TEAM_TYCD = #{teamCtgrCd}
LEFT JOIN TB_HOME_BBS_RLTN C ON A.TEAM_ID = C.RLTN_REF_CD AND C.CONTS_TYCD = 'TEAM'
AND EXISTS ( SELECT 1 FROM TB_LMS_TEAM_MBR AA WHERE TEAM_ID = A.TEAM_ID AND USER_ID = #{userId} AND EXISTS ( SELECT 1 FROM TB_LMS_ATNDLC_SBJCT WHERE USER_ID = AA.USER_ID AND ORG_ID = #{orgId} AND STD_ID = AA.STD_ID AND SBJCT_ID = #{crsCreCd} AND ATNDLC_STSCD = 'S' ) )

/* SQL ID : BbsInfoDAO.selectTeamBbsInfo 설 명 : 팀 게시판 조회 */ SELECT A.TEAM_ID , A.TEAMNM , C.BBS_ID FROM TB_LMS_TEAM A JOIN TB_LMS_TEAM_CTGR B ON A.TEAM_TYCD = B.TEAM_TYCD AND B.TEAM_BBS_YN = 'Y' AND B.TEAM_CPST_CMPTNYN = 'Y'
AND A.TEAM_TYCD = #{teamCtgrCd}
JOIN TB_HOME_BBS_RLTN C ON A.TEAM_ID = C.RLTN_REF_CD AND C.CONTS_TYCD = 'TEAM' WHERE A.TEAM_ID = #{teamCd}

		/*
             SQL ID : BbsInfoDAO.countTeamBbsMember
             설  명 : 게시판 팀원여부 체크
         */
		SELECT COUNT(1) AS CNT
		FROM TB_HOME_BBS_RLTN A
		JOIN TB_LMS_TEAM B
		ON A.RLTN_REF_CD = B.TEAM_ID
		AND B.TEAM_ID = #{teamCd}
		WHERE A.CONTS_TYCD = 'TEAM'
		AND EXISTS (
			SELECT 1
			FROM TB_LMS_TEAM_CTGR
			WHERE TEAM_TYCD = B.TEAM_TYCD
			AND ORG_ID = #{orgId}
			AND SBJCT_ID = #{crsCreCd}
			AND TEAM_TYCD = #{teamCtgrCd}
			AND TEAM_BBS_YN = 'Y'
			AND TEAM_CPST_CMPTNYN = 'Y'
		)
		AND EXISTS (
			SELECT 1
			FROM TB_LMS_TEAM_MBR AA
			WHERE TEAM_ID = B.TEAM_ID
			AND USER_ID = #{userId}
			AND EXISTS (
				SELECT 1
				FROM TB_LMS_ATNDLC_SBJCT
				WHERE USER_ID = AA.USER_ID
				AND STD_ID = AA.STD_ID
				AND SBJCT_ID = #{crsCreCd}
				AND ORG_ID = #{orgId}
				AND ATNDLC_STSCD = 'S'
			)
		)

/* SQL ID : BbsInfoDAO.selectBbsInfoByOldRegDttm 설 명 : 게시판 코드별 생성일 빠른 게시판 조회 */ SELECT A.* , B.CRS_ID FROM ( SELECT A.BBS_ID AS bbsId , A.ORG_ID AS orgId , A.BBS_ID AS bbsCd , IF(A.BBS_ID = 'TEAM', (SELECT AA.SBJCT_ID FROM TB_LMS_TEAM_CTGR AA JOIN TEAM BB ON AA.TEAM_TYCD = BB.TEAM_TYCD AND BB.TEAM_ID = B.RLTN_REF_CD), B.RLTN_REF_CD) AS SBJCT_ID FROM TB_LMS_BBS A JOIN TB_HOME_BBS_RLTN AS B ON A.BBS_ID = B.BBS_ID LEFT JOIN TB_HOME_BBS_INFO_LANG AS C ON A.BBS_ID = C.BBS_ID AND C.LANG_CD = #{langCd} WHERE A.DELYN = 'N' AND A.ORG_ID = #{orgId}
AND A.BBS_ID = #{bbsCd}
AND B.RLTN_REF_CD = #{crsCreCd}
AND A.USEYN = #{useYn}
AND A.SYS_USEYN = #{sysUseYn}
ORDER BY A.FRST_INQ_DTTM LIMIT 1 ) A LEFT JOIN TB_LMS_SBJCT B ON A.SBJCT_ID = B.SBJCT_ID
